form:Form.form:Scripts:
		var nSQL;
var np;
function onLoad()
{ 
	//alert(Ctrl("hidOICarpeta").GetXValue()); 

	//Recupera datos comunes a todos los modos
	var xmlParam = new NomadXML("PARAMS");
	xmlParam.SetAttr("oi_tarea",Ctrl("oi_tarea").GetXValue());       
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	var estado = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ULT_ESTADO"), xmlParam.ToString());
	//Ctrl("oi_est_car_ant").SetXValue(estado.oi_estado_carpeta); 
	Ctrl("oi_estado_tarea_anterior").SetXValue(estado.oi_estado_tarea);	      	 


	var tipo_tarea = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ULT_TIPO"), xmlParam.ToString());  
	//Ctrl("hid_oi_tipo_carpeta").SetXValue(tipo_carpeta.oi_tipo_carpeta);	
	Ctrl("tipo_tarea").SetXValue(tipo_tarea.c_tipo_tarea);	

}

function  estado_tarea_validate()
{
  var estado=Ctrl('oi_estado_tarea_nuevo').GetXValue().substring(0,1);
	var estado_ant=Ctrl('oi_estado_tarea_anterior').GetXValue().substring(0,1);

 	if(Ctrl('tipo_tarea').GetXValue()=="13")
	{ 
	  if(estado=="2")
		{
			alert("Solo se puede cambiar a estado 1-A completar, 3-Cumplida o 4-Cancelada");
	 		CtrlEnabled("ACEPTAR",false);
	 		return false;
	  }
	 	else
	 	{
	 		CtrlEnabled("ACEPTAR",true);
	 	}	
	}
	if(estado==estado_ant)
	{
		alert("Está intentando realizar un cambio al mismo estado de tarea");
		CtrlEnabled("ACEPTAR",false);
		return false;
	}    
	else
	{
	 		CtrlEnabled("ACEPTAR",true);
	}	
}

function estado_tarea_valido()
{   
	var estado=Ctrl('oi_estado_tarea_nuevo').GetXValue().substring(0,1);
	var estado_ant=Ctrl('oi_estado_tarea_anterior').GetXValue().substring(0,1);

  if(estado==estado_ant)
	{
		alert("Está intentando realizar un cambio al mismo estado de tarea");
		CtrlEnabled("ACEPTAR",false);
		return false;
	}
	else
	{
		CtrlEnabled("ACEPTAR",true);
	}	   
}
